export default function QuinielaMundial() {
  const [page, setPage] = useState('invitacion');
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [codigoIngresado, setCodigoIngresado] = useState('');
  const [codigoError, setCodigoError] = useState('');
  const [email, setEmail] = useState('');
  const [nombre, setNombre] = useState('');
  const [password, setPassword] = useState('');
  const [isLogin, setIsLogin] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const [predicciones, setPredicciones] = useState({});
  const [guardadas, setGuardadas] = useState(false);
  const [expandedGrupo, setExpandedGrupo] = useState('A');

  const validarCodigo = (e) => {
    e.preventDefault();
    setCodigoError('');
    if (CODIGOS_VALIDOS.includes(codigoIngresado.toUpperCase())) {
      setPage('auth');
      setCodigoIngresado('');
    } else {
      setCodigoError('❌ Código inválido');
      setCodigoIngresado('');
    }
  };

  const handleAuth = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      setUser({ email, nombre });
      setPage('predicciones');
      setLoading(false);
    }, 500);
  };

  const handleLogout = () => {
    setUser(null);
    setPage('invitacion');
  };

  const handlePrediccionChange = (id, field, value) => {
    setPredicciones(prev => ({
      ...prev,
      [id]: { ...prev[id], [field]: value }
    }));
    setGuardadas(false);
  };

  const guardarPredicciones = () => {
    setLoading(true);
    setTimeout(() => {
      setGuardadas(true);
      setLoading(false);
      alert('✅ ¡Predicciones guardadas!');
    }, 800);
  };

  // PÁGINA INVITACIÓN - CON TU IMAGEN LTC
  if (page === 'invitacion') {
    return (
      <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0a1628 0%, #1a2847 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px', fontFamily: 'system-ui' }}>
        <div style={{ background: '#1a2847', border: '2px solid #f0a500', borderRadius: '16px', padding: '40px', maxWidth: '550px', width: '100%' }}>
          
          {/* IMAGEN LTC - INTEGRADA */}
          <div style={{ marginBottom: '24px', textAlign: 'center' }}>
            <img 
              src=""
              alt="Local Trading Colombia"
              style={{ maxWidth: '100%', maxHeight: '200px', borderRadius: '12px', boxShadow: '0 10px 30px rgba(240, 165, 0, 0.3)', objectFit: 'contain' }}
            />
          </div>

          <div style={{ textAlign: 'center', marginBottom: '30px' }}>
            <h1 style={{ fontSize: '28px', fontWeight: 'bold', color: '#f0a500', margin: 0 }}>QUINIELA MUNDIAL 2026</h1>
            <p style={{ color: '#8b949e', margin: '12px 0 0 0', fontSize: '13px' }}>Acceso restringido</p>
          </div>

          <div style={{ background: '#0d1117', padding: '20px', borderRadius: '12px', marginBottom: '20px', borderLeft: '4px solid #58a6ff' }}>
            <div style={{ fontSize: '13px', color: '#8b949e', marginBottom: '8px' }}>📌 CÓDIGO DE INVITACIÓN REQUERIDO</div>
            <div style={{ fontSize: '12px', color: '#6e7681' }}>Si no tienes acceso, solicita a: admin@localtrading.com</div>
          </div>

          <form onSubmit={validarCodigo} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            <div>
              <label style={{ fontSize: '12px', color: '#8b949e', display: 'block', marginBottom: '8px' }}>🔑 CÓDIGO</label>
              <input type="text" placeholder="Ej: MUNDIAL2026" value={codigoIngresado} onChange={(e) => setCodigoIngresado(e.target.value.toUpperCase())} required style={{ background: '#161b22', border: codigoError ? '2px solid #f85149' : '1px solid #30363d', color: '#e6edf3', padding: '12px', borderRadius: '8px', fontSize: '14px', boxSizing: 'border-box', width: '100%' }} />
            </div>

            {codigoError && (
              <div style={{ background: '#f85149', color: 'white', padding: '12px', borderRadius: '6px', fontSize: '12px', textAlign: 'center' }}>
                {codigoError}
              </div>
            )}

            <button type="submit" style={{ background: '#f0a500', border: 'none', color: '#0f0c1f', padding: '12px', borderRadius: '8px', fontSize: '16px', fontWeight: '600', cursor: 'pointer' }}>
              ✓ VERIFICAR CÓDIGO
            </button>
          </form>

          <div style={{ marginTop: '20px', padding: '16px', background: '#21262d', borderRadius: '8px', borderLeft: '4px solid #3fb950' }}>
            <div style={{ fontSize: '12px', color: '#8b949e', marginBottom: '8px' }}>💡 CÓDIGOS DE DEMO:</div>
            <div style={{ fontSize: '12px', color: '#e6edf3', fontFamily: 'monospace', display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
              <code style={{ background: '#0d1117', padding: '4px 8px', borderRadius: '4px' }}>MUNDIAL2026</code>
              <code style={{ background: '#0d1117', padding: '4px 8px', borderRadius: '4px' }}>QUINIELAOK</code>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (page === 'auth') {
    return (
      <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0a1628 0%, #1a2847 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px', fontFamily: 'system-ui' }}>
        <div style={{ background: '#1a2847', border: '1px solid #2d1f4a', borderRadius: '16px', padding: '40px', maxWidth: '500px', width: '100%' }}>
          <div style={{ textAlign: 'center', marginBottom: '30px' }}>
            <div style={{ fontSize: '56px', marginBottom: '16px' }}>⚽</div>
            <h1 style={{ fontSize: '28px', fontWeight: 'bold', color: '#f0a500', margin: 0 }}>QUINIELA MUNDIAL 2026</h1>
            <p style={{ color: '#8b949e', margin: '8px 0 0 0', fontSize: '13px' }}>Predicciones + Ranking</p>
          </div>

          <form onSubmit={handleAuth} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {!isLogin && (
              <input type="text" placeholder="Tu nombre" value={nombre} onChange={(e) => setNombre(e.target.value)} required style={{ background: '#161b22', border: '1px solid #30363d', color: '#e6edf3', padding: '12px', borderRadius: '8px', fontSize: '14px', boxSizing: 'border-box' }} />
            )}

            <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required style={{ background: '#161b22', border: '1px solid #30363d', color: '#e6edf3', padding: '12px', borderRadius: '8px', fontSize: '14px', boxSizing: 'border-box' }} />

            <div style={{ position: 'relative' }}>
              <input type={showPassword ? 'text' : 'password'} placeholder="Contraseña" value={password} onChange={(e) => setPassword(e.target.value)} required style={{ background: '#161b22', border: '1px solid #30363d', color: '#e6edf3', padding: '12px', borderRadius: '8px', fontSize: '14px', width: '100%', boxSizing: 'border-box' }} />
              <button type="button" onClick={() => setShowPassword(!showPassword)} style={{ position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: '#8b949e', cursor: 'pointer' }}>
                {showPassword ? '🙈' : '👁️'}
              </button>
            </div>

            <button type="submit" disabled={loading} style={{ background: '#f0a500', border: 'none', color: '#0f0c1f', padding: '12px', borderRadius: '8px', fontSize: '16px', fontWeight: '600', cursor: 'pointer', opacity: loading ? 0.7 : 1 }}>
              {loading ? 'Cargando...' : isLogin ? 'Iniciar Sesión' : 'Registrarse'}
            </button>
          </form>

          <button onClick={() => setIsLogin(!isLogin)} style={{ background: 'none', border: 'none', color: '#58a6ff', cursor: 'pointer', fontSize: '14px', marginTop: '16px', width: '100%' }}>
            {isLogin ? '¿No tienes cuenta? Crea una' : '¿Ya tienes cuenta? Inicia sesión'}
          </button>

          <button onClick={() => setPage('invitacion')} style={{ background: 'none', border: 'none', color: '#f85149', cursor: 'pointer', fontSize: '12px', marginTop: '12px', width: '100%', textDecoration: 'underline' }}>
            ← Volver
          </button>
        </div>
      </div>
    );
  }

  if (page === 'predicciones') {
    const grupos = {};
    TODOS_LOS_PARTIDOS.forEach(p => {
      if (!grupos[p.grupo]) grupos[p.grupo] = [];
      grupos[p.grupo].push(p);
    });

    return (
      <div style={{ minHeight: '100vh', background: '#0d1117', color: '#e6edf3', padding: '20px', fontFamily: 'system-ui' }}>
        <div style={{ maxWidth: '1400px', margin: '0 auto' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px', paddingBottom: '20px', borderBottom: '1px solid #30363d' }}>
            <div>
              <h1 style={{ fontSize: '32px', fontWeight: 'bold', color: '#f0a500', margin: 0 }}>MUNDIAL 2026</h1>
              <p style={{ color: '#8b949e', fontSize: '13px', margin: '4px 0 0 0' }}>Hola, {user?.nombre}</p>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setPage('dashboard')} style={{ background: '#58a6ff', border: 'none', color: '#0d1117', padding: '10px 16px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '13px' }}>📊 Dashboard</button>
              <button onClick={handleLogout} style={{ background: '#f85149', border: 'none', color: 'white', padding: '10px 16px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '13px' }}>🚪 Salir</button>
            </div>
          </div>

          {guardadas && <div style={{ background: '#1f6feb', color: 'white', padding: '12px 16px', borderRadius: '6px', marginBottom: '20px', fontSize: '13px' }}>✅ Predicciones guardadas</div>}

          <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', overflowX: 'auto', paddingBottom: '8px', borderBottom: '1px solid #30363d' }}>
            {['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J', 'K', 'L'].map(g => (
              <button key={g} onClick={() => setExpandedGrupo(g)} style={{ background: expandedGrupo === g ? '#f0a500' : '#161b22', color: expandedGrupo === g ? '#0f0c1f' : '#8b949e', border: 'none', padding: '10px 16px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '14px' }}>
                GRUPO {g}
              </button>
            ))}
          </div>

          <div style={{ marginBottom: '100px' }}>
            {grupos[expandedGrupo]?.map((partido) => (
              <div key={partido.id} style={{ background: '#161b22', border: '1px solid #30363d', borderRadius: '12px', padding: '20px', marginBottom: '16px' }}>
                <div style={{ marginBottom: '16px' }}>
                  <div style={{ fontSize: '14px', fontWeight: '600', color: '#e6edf3' }}>{partido.equipo1} vs {partido.equipo2}</div>
                  <div style={{ fontSize: '11px', color: '#8b949e', marginTop: '4px' }}>{partido.fecha} • {partido.hora_local}</div>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))', gap: '12px' }}>
                  <input type="number" min="0" placeholder="Goles E1" value={predicciones[partido.id]?.m_e1 ?? ''} onChange={(e) => handlePrediccionChange(partido.id, 'm_e1', e.target.value)} style={{ background: '#0d1117', border: '1px solid #30363d', color: '#f0a500', padding: '8px', borderRadius: '4px', textAlign: 'center' }} />
                  <input type="number" min="0" placeholder="Goles E2" value={predicciones[partido.id]?.m_e2 ?? ''} onChange={(e) => handlePrediccionChange(partido.id, 'm_e2', e.target.value)} style={{ background: '#0d1117', border: '1px solid #30363d', color: '#f0a500', padding: '8px', borderRadius: '4px', textAlign: 'center' }} />
                </div>
              </div>
            ))}
          </div>

          <div style={{ position: 'fixed', bottom: '20px', right: '20px' }}>
            <button onClick={guardarPredicciones} disabled={loading} style={{ background: '#3fb950', border: 'none', color: 'white', padding: '14px 24px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', fontSize: '14px' }}>
              💾 Guardar Todo
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (page === 'dashboard') {
    return (
      <div style={{ minHeight: '100vh', background: '#0d1117', color: '#e6edf3', padding: '20px', fontFamily: 'system-ui' }}>
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
            <h1 style={{ fontSize: '32px', fontWeight: 'bold', color: '#f0a500', margin: 0 }}>RANKING</h1>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setPage('predicciones')} style={{ background: '#58a6ff', border: 'none', color: '#0d1117', padding: '10px 16px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600' }}>⚽ Predicciones</button>
              <button onClick={handleLogout} style={{ background: '#f85149', border: 'none', color: 'white', padding: '10px 16px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600' }}>🚪 Salir</button>
            </div>
          </div>

          <div style={{ background: 'linear-gradient(135deg, #1a2847 0%, #2d3f5a 100%)', border: '2px solid #f0a500', borderRadius: '12px', padding: '32px', marginBottom: '30px', textAlign: 'center' }}>
            <div style={{ fontSize: '20px', fontWeight: '600', color: '#f0a500', marginBottom: '8px' }}>🏆 MIS PUNTOS</div>
            <div style={{ fontSize: '64px', fontWeight: 'bold', color: '#f0a500' }}>0</div>
          </div>

          <div style={{ background: '#161b22', border: '1px solid #30363d', borderRadius: '8px', overflow: 'hidden' }}>
            <div style={{ background: '#21262d', padding: '16px', display: 'grid', gridTemplateColumns: '60px 1fr 120px', gap: '16px', fontWeight: '600', fontSize: '13px', color: '#8b949e' }}>
              <div>POS</div>
              <div>PARTICIPANTE</div>
              <div style={{ textAlign: 'right' }}>PUNTOS</div>
            </div>

            {[
              { nombre: 'Juan Pérez', email: 'juan@example.com', puntos: 85 },
              { nombre: 'María García', email: 'maria@example.com', puntos: 78 },
              { nombre: user?.nombre, email: user?.email, puntos: 0 },
            ].sort((a, b) => (b.puntos || 0) - (a.puntos || 0)).map((r, idx) => (
              <div key={idx} style={{ padding: '16px', display: 'grid', gridTemplateColumns: '60px 1fr 120px', gap: '16px', background: r.email === user?.email ? '#21262d' : 'transparent' }}>
                <div style={{ fontSize: '14px', fontWeight: 'bold', color: '#f0a500' }}>{idx === 0 ? '🥇' : idx === 1 ? '🥈' : `${idx + 1}.`}</div>
                <div style={{ fontSize: '14px', color: '#e6edf3' }}>{r.nombre}</div>
                <div style={{ fontSize: '16px', fontWeight: 'bold', color: '#3fb950', textAlign: 'right' }}>{r.puntos}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }
}
